SELECT "POSTAL_CODE", "DATE_VALID_STD", "TOT_SNOWFALL_IN" FROM "GLOBAL_WEATHER__CLIMATE_DATA_FOR_BI"."STANDARD_TILE"."HISTORY_DAY" WHERE "COUNTRY" = 'US' AND "TOT_SNOWFALL_IN" > 6 AND "DATE_VALID_STD" BETWEEN DATEADD(day, 14, DATE_FROM_PARTS(EXTRACT(YEAR FROM DATE '2024-04-01') - 1, 1, 1)) AND DATEADD(day, 20, DATE_FROM_PARTS(EXTRACT(YEAR FROM DATE '2024-04-01') - 1, 1, 1))